  ('customs-f19eb2bd-moex-00257', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '關於測深儀原理的敘述，下列何者錯誤？', '["聲波在水中的波速約為1500公尺/秒", "水中的聲波速度與溫度、鹽度及壓力有關", "測深儀使用超聲波（Ultrasonicwave）可以減少俥葉震動的干擾", "超聲波在水中傳播的速度較人類在水中可以聽到的聲波速度快"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00258', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '造成全球定位系統（GPS）誤差的原因，下列何者係可以經由船上接收機計算以降低定位誤差？', '["大氣層延遲誤差", "多路徑誤差", "衛星時鐘誤差", "幾何精度稀釋誤差"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00259', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '海上人命安全國際公約（SOLAS）關於船舶自動識別系統（AIS）的規範，下列何者錯誤？', '["所有客船，總噸300含以上航行國際航線貨船與總噸500含以上非航行國際航線貨船均應裝設AIS", "AIS應自動提供岸上站台、其他船舶與飛行器包含船舶識別等資訊", "AIS也能自動接收其他裝設有AIS船舶的資訊", "船長為了維持商業機密可以隨時關閉AIS"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00260', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '國際海事組織（IMO）關於電子海圖顯示與資訊系統（ECDIS）之顯示內容，下列敘述何者錯誤？', '["必須提供基本顯示、標準顯示與其他資訊三種資料量的選擇", "海岸線、本船安全等深線與安全水域內的孤立危險物屬於基本顯示內容", "海底電纜與管線及磁差屬於標準顯示內容", "經緯線與地名屬於其他資訊內容"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00261', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '船舶設備規則對於航線的定義，下列何者錯誤？', '["在日月潭航行的客船屬於內水航線", "布袋港至馬公港航行的客船屬於沿海航線", "高雄港至金門港航行的貨船屬於外海航線", "基隆港至日本鹿耳島港的航線屬於國際航線"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00262', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '關於船體結構名詞，下列敘述何者錯誤？', '["主甲板（maindeck）為最主要的一層連續甲板，由船首一直舖設至船尾，且延伸至兩舷", "艏艛甲板（Forecastledeck）位於船艏艛上的間斷甲板，延伸至兩舷", "上層建築甲板（Superstructuredeck）係位於主甲板或上甲板上之連續甲板，延伸至兩舷", "露天甲板（Weatherdeck）指暴露無遮蔽之甲板，受風雨海浪侵襲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00263', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '關於載重線標誌的敘述，下列何者錯誤？', '["甲板線（Deckline）標於船舯兩舷外板上的橫線，其中心與載重線圈中心的垂直距離為夏季乾舷值", "夏期載重線上緣與夏期淡水載重線上緣的垂直距離一般稱為淡水修正量（FWA）", "夏期載重線上緣與夏期淡水載重線上緣的垂直距離相當於熱帶載重線上緣至熱帶淡水載重線上緣的垂 直距離", "運送木材時，船舶之法定乾舷可以比其在運送其他貨物之法定乾舷小"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00264', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '某船艏平均吃水為4.85公尺，舯平均吃水為5.02公尺，艉平均吃水為5.45公尺，則下列何者錯誤？', '["該船俯仰差艉坐0.6公尺（Trimbystern）", "該船平均吃水（mean）為5.15公尺", "該船呈現舯垂（Sagging）狀態", "該船上甲板受張力（Tension），船底板受壓縮力（Compression）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00265', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '關於船舶繫纜的名稱與功能，下列何者錯誤？', '["艏纜（Headline）用以防止船舶向後移動，並用來調整船席位置", "橫纜（Breast）用以拉住船體靠攏碼頭，並防止前後移動", "倒纜（Spring）用以協助艏纜、橫纜與艉纜，防止前後移動並緊靠碼頭", "艉纜（Sternline）用以防止船舶向前移動，並用來調整船席位置"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00266', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '關於舵令（Rudderorder）的標準用語與意義，下列何者錯誤？', '["右滿舵（Hardstarboard），將舵向右轉動至舵角35度", "正舵（Midships），將舵輪轉回至正中位置，即舵角0度", "穩舵（Steady），在大角度轉向後回轉舵輪至相同一方較小角度時使用以減低擺動", "反舵（Shifttherudder），將舵角轉至原來發出舵令之相反方向舵令，如原為右舵10度，則轉舵輪至左 舵10度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL)
